4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	function calculateItemPremium(item: any): number {
14	  const base = BASE_PREMIUMS[item.type];
15	  if (item.cursed) {
16	    return base + base * 0.5;
17	  }
18	  return base;
19	}
20	
21	export function claimOffice(input: any): unknown {
22	  const items = input.steps[0].items;
23	  let itemsTotal = items.reduce(
24	    (sum: number, item: any) => sum + calculateItemPremium(item),
25	    0,
26	  );
27	
28	  const typeCounts: Record<string, number> = {};
29	  for (const item of items) {
30	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
31	  }
32	  for (const type in typeCounts) {
33	    if (typeCounts[type] === 3) {
34	      itemsTotal = itemsTotal - (3 * BASE_PREMIUMS[type]) + BLOCK_OF_THREE_PRICE;
35	    }
36	  }
37	
38	  const premium = itemsTotal + PROCESSING_FEE;
39	  return { results: [{ premium }] };
40	}
